sql:
SELECT DISTINCT country
FROM epidemiological_data
WHERE disease_name = 'COVID-19';

external_knowledge:
- 'beacons of truth' refers to the diseases with a high verification rate of data;
- 'total light of confirmed cases' represents the total number of confirmed cases for each disease;
- 'shone brighter than half the total light of confirmed cases' means the verification rate of data is more than 50%.

sql:
SELECT country
FROM epidemiological_data
WHERE active_cases > (SELECT AVG(active_cases) FROM epidemiological_data);

SELECT data_id, country, cases, deaths, region, timestamp, disease_name 
FROM epidemiological_data
ORDER BY timestamp DESC;

SELECT AVG(latitude) AS average_latitude, AVG(longitude) AS average_longitude
FROM epidemiological_data
WHERE disease_name = 'COVID-19' AND is_verified = 1;
